import{_ as t,c as i,S as s,o as a}from"./chunks/framework.BjmDYXuv.js";const u=JSON.parse('{"title":"Local Simulation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/simulation.md","filePath":"guide/simulation.md","lastUpdated":1776176539000}'),n={name:"guide/simulation.md"};function l(o,e,r,h,d,p){return a(),i("div",null,e[0]||(e[0]=[s(`<h1 id="local-simulation" tabindex="-1">Local Simulation <a class="header-anchor" href="#local-simulation" aria-label="Permalink to &quot;Local Simulation&quot;">​</a></h1><p>ColliderML can generate new events on your own machine using the full physics pipeline: Pythia (or MadGraph + Pythia for NLO processes) → Geant4 detector simulation via DDSim → digitisation and track reconstruction via ACTS → parquet conversion. Everything runs inside the official OpenDataDetector software container, so you do not need to install any HEP tooling yourself — just Docker or Podman.</p><p>This page covers the <strong>local</strong> story: running the pipeline on your own workstation or a shared node. If you would rather hand the work off to a shared cluster, see <a href="./remote-simulation.html">Remote Simulation</a>.</p><h2 id="when-to-run-locally" tabindex="-1">When to run locally <a class="header-anchor" href="#when-to-run-locally" aria-label="Permalink to &quot;When to run locally&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Use local simulation when</th><th style="text-align:left;">Use remote simulation when</th></tr></thead><tbody><tr><td style="text-align:left;">You want tight iteration on a few events</td><td style="text-align:left;">You need &gt;100 events with pileup</td></tr><tr><td style="text-align:left;">You have Docker / Podman + ~20 GB free disk</td><td style="text-align:left;">You do not have a container runtime</td></tr><tr><td style="text-align:left;">You want offline reproducibility</td><td style="text-align:left;">You want someone else to pay the compute bill</td></tr><tr><td style="text-align:left;">You are debugging a pipeline change</td><td style="text-align:left;">You are running a benchmark</td></tr></tbody></table><p>A typical iteration loop — <code>simulate → inspect → tweak → simulate again</code> — fits comfortably within 10–15 minutes for the <code>*-quick</code> presets.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ol><li><strong>Python 3.10 or newer</strong> — see <a href="./installation.html">Installation</a>.</li><li><strong>Either Docker or Podman</strong> on your <code>$PATH</code>. The library auto-detects whichever is installed; Docker is preferred if both are present.</li><li><strong>Disk headroom</strong>: <ul><li>~10 GB for the OpenDataDetector software image (pulled once)</li><li>~2 GB for the Geant4 physics data tables (downloaded on first run)</li><li>50 MB to a few hundred MB per run, depending on event count</li></ul></li><li>The simulate extras installed:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install &quot;colliderml[sim]&quot;</span></span></code></pre></div></li></ol><h2 id="the-first-run-annotated" tabindex="-1">The first run, annotated <a class="header-anchor" href="#the-first-run-annotated" aria-label="Permalink to &quot;The first run, annotated&quot;">​</a></h2><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> colliderml</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">result </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> colliderml.simulate(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">preset</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ttbar-quick&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(result.run_dir)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([p.name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> p </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> result.list_files()])</span></span></code></pre></div><p>On first invocation, <code>simulate()</code> will:</p><ol><li><strong>Detect the container runtime</strong> (<code>docker</code> or <code>podman</code>). If neither is available you get a clear error pointing at <a href="./remote-simulation.html">Remote Simulation</a> instead.</li><li><strong>Prompt before pulling</strong> the ~10 GB container image (skipped in non-interactive environments — pass <code>image=&quot;...&quot;</code> to override the pinned tag).</li><li><strong>Clone <code>colliderml-production</code></strong> into <code>~/.cache/colliderml/simulate/colliderml-production/</code>. This repo holds the stage scripts, YAML config templates, and container bootstrap script. It is pinned to a known-good git ref for reproducibility.</li><li><strong>Clone OpenDataDetector v4.0.4</strong> (CERN GitLab) and <strong>MG5aMC_PY8_interface</strong> (GitHub) into the same cache directory. These provide the detector geometry and MadGraph/Pythia bridge that the container expects at <code>/cache/odd-v4</code> and <code>/cache/MG5aMC_PY8_interface</code>.</li><li><strong>Run each pipeline stage</strong> in order. Progress is printed to stdout; the first stage typically takes a few seconds, detector sim is the long pole (~10 minutes for 10 events).</li><li><strong>Return a <code>SimulationResult</code></strong> with paths to the outputs.</li></ol><p>Everything cached in step 2–4 persists between runs, so the <em>second</em> invocation skips straight to step 5 and starts producing events immediately.</p><h2 id="presets-versus-explicit-parameters" tabindex="-1">Presets versus explicit parameters <a class="header-anchor" href="#presets-versus-explicit-parameters" aria-label="Permalink to &quot;Presets versus explicit parameters&quot;">​</a></h2><p>Presets are named shorthand for common workloads:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Preset: bundled (channel, events, pileup) triple.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">colliderml.simulate(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">preset</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ttbar-quick&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Explicit parameters.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">colliderml.simulate(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">channel</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;higgs_portal&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">events</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">pileup</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Preset as a starting point, but bump pileup:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">colliderml.simulate(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">preset</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ttbar-quick&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">pileup</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">40</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Explicit arguments always win over the preset&#39;s defaults. List the full preset catalogue on the CLI:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">colliderml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list-presets</span></span></code></pre></div><h2 id="what-comes-out" tabindex="-1">What comes out <a class="header-anchor" href="#what-comes-out" aria-label="Permalink to &quot;What comes out&quot;">​</a></h2><p><code>SimulationResult.run_dir</code> points at a per-run directory (e.g. <code>colliderml_output/ttbar_pu0_10evt/runs/0/</code>) containing:</p><table><thead><tr><th style="text-align:left;">File</th><th style="text-align:left;">Stage</th><th style="text-align:left;">Format</th></tr></thead><tbody><tr><td style="text-align:left;"><code>events.hepmc.gz</code></td><td style="text-align:left;">MadGraph (ttbar only)</td><td style="text-align:left;">HepMC2</td></tr><tr><td style="text-align:left;"><code>merged_events.hepmc3</code></td><td style="text-align:left;">Pythia + pileup</td><td style="text-align:left;">HepMC3</td></tr><tr><td style="text-align:left;"><code>edm4hep.root</code></td><td style="text-align:left;">DDSim / Geant4</td><td style="text-align:left;">EDM4hep ROOT</td></tr><tr><td style="text-align:left;"><code>measurements.root</code></td><td style="text-align:left;">Digitisation</td><td style="text-align:left;">ACTS ROOT</td></tr><tr><td style="text-align:left;"><code>particles.root</code></td><td style="text-align:left;">Truth particles</td><td style="text-align:left;">ACTS ROOT</td></tr><tr><td style="text-align:left;"><code>tracksummary_ambi.root</code></td><td style="text-align:left;">Reconstruction</td><td style="text-align:left;">ACTS ROOT</td></tr><tr><td style="text-align:left;"><code>*.parquet</code></td><td style="text-align:left;">Parquet conversion</td><td style="text-align:left;">Parquet</td></tr></tbody></table><p>The parquet outputs can be loaded with the same <a href="./../library/loading.html"><code>colliderml.load()</code></a> helper used for the released dataset, so downstream analysis code does not care whether the events came from HuggingFace or from your own machine.</p><h2 id="cache-layout-and-disk-hygiene" tabindex="-1">Cache layout and disk hygiene <a class="header-anchor" href="#cache-layout-and-disk-hygiene" aria-label="Permalink to &quot;Cache layout and disk hygiene&quot;">​</a></h2><p>Everything is rooted at <code>$COLLIDERML_CACHE</code> (defaults to <code>~/.cache/colliderml/</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>~/.cache/colliderml/simulate/</span></span>
<span class="line"><span>├── colliderml-production/          # pinned production-repo clone</span></span>
<span class="line"><span>│   └── .cache/</span></span>
<span class="line"><span>│       ├── odd-v4/                 # OpenDataDetector geometry</span></span>
<span class="line"><span>│       ├── g4data/                 # Geant4 physics tables (~2 GB)</span></span>
<span class="line"><span>│       └── MG5aMC_PY8_interface/   # MG5 → Pythia bridge</span></span></code></pre></div><p>Wipe the whole tree at any time — <code>simulate()</code> will re-populate it on the next run. If a stage complains that a cache is corrupt, call <code>colliderml.simulate.docker.clone_colliderml_production(force_refresh=True)</code> to re-fetch just the production-repo clone.</p><h2 id="overriding-the-pinned-pipeline-ref" tabindex="-1">Overriding the pinned pipeline ref <a class="header-anchor" href="#overriding-the-pinned-pipeline-ref" aria-label="Permalink to &quot;Overriding the pinned pipeline ref&quot;">​</a></h2><p>The pinned <code>colliderml-production</code> ref is a module-level constant in <a href="./../library/simulate.html#auto-cloning-the-production-repo"><code>colliderml.simulate.docker</code></a>. To point at an in-flight branch of the production repo without editing the library:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> COLLIDERML_PRODUCTION_REF</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">my-feature-branch</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;import colliderml; colliderml.simulate(preset=&#39;ttbar-quick&#39;)&quot;</span></span></code></pre></div><p>This is the supported escape hatch for pipeline developers working on both repos at once; end users should stick with the pinned default.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p><strong>&quot;Neither docker nor podman is installed.&quot;</strong> — install one of them, or run remotely with <code>simulate(..., remote=True)</code>.</p><p><strong>&quot;daemon is not responding&quot;</strong> — Docker Desktop needs to be running (on macOS/Windows) or the <code>dockerd</code> service needs to be up (on Linux). Try <code>docker info</code> from a shell to confirm.</p><p><strong>First run gets stuck on &quot;Pulling …&quot;</strong> — the OpenDataDetector image is ~10 GB. Check your connection and let it finish; subsequent runs reuse the cached image.</p><p><strong>Stage fails with <code>libOpenDataDetector.so not found</code></strong> — the production checkout in the cache is corrupt. Re-clone with <code>force_refresh=True</code>, or delete <code>~/.cache/colliderml/simulate/</code> and let <code>simulate()</code> start fresh.</p><p><strong>&quot;No stages were generated&quot;</strong> — the pinned production-repo ref is missing config YAML files for the requested channel. Bump <code>COLLIDERML_PRODUCTION_REF</code> to a newer ref, or file an issue.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li>Run the CLI equivalent: <a href="./../library/cli.html#simulate"><code>colliderml simulate</code></a></li><li>Look up the <code>simulate()</code> signature: <a href="./../library/simulate.html">Simulate API</a></li><li>Pipe the outputs into a benchmark: <a href="./tasks.html">Benchmark Tasks</a></li><li>Offload heavy runs: <a href="./remote-simulation.html">Remote Simulation</a></li></ul>`,38)]))}const g=t(n,[["render",l]]);export{u as __pageData,g as default};
